class EventEmitter {
  constructor() { this.events = new Map(); }

  on(name, fn) {
    if (!this.events.has(name)) this.events.set(name, new Set());
    this.events.get(name).add(fn);
    return this;
  }

  off(name, fn) {
    this.events.get(name)?.delete(fn);
    return this;
  }

  emit(name, ...args) {
    // copy so a listener that unsubscribes mid-emit doesn't skip others
    for (const fn of [...(this.events.get(name) ?? [])]) fn.apply(this, args);
    return this;
  }

  once(name, fn) {
    const wrap = (...args) => { this.off(name, wrap); fn.apply(this, args); };
    return this.on(name, wrap);
  }
}

function promiseAll(promises) {
  return new Promise((resolve, reject) => {
    const results = [];
    let remaining = promises.length;
    if (remaining === 0) return resolve(results);
    promises.forEach((p, i) => {
      Promise.resolve(p).then((value) => {
        results[i] = value;
        if (--remaining === 0) resolve(results);
      }, reject);
    });
  });
}

function deepEqual(a, b) {
  if (a === b) return true;
  if (typeof a !== 'object' || typeof b !== 'object' || a === null || b === null) {
    return false;
  }
  const keysA = Object.keys(a);
  const keysB = Object.keys(b);
  if (keysA.length !== keysB.length) return false;
  return keysA.every(
    (k) => Object.prototype.hasOwnProperty.call(b, k) && deepEqual(a[k], b[k])
  );
}

class TicTacToe {
  constructor() {
    this.board = Array(9).fill(null);
    this.turn = 'X';
    this.winner = null; // 'X' | 'O' | 'draw' | null
  }

  move(i) {
    if (this.winner || this.board[i]) return false; // game over or taken
    this.board[i] = this.turn;
    this.winner = this.checkWinner();
    if (!this.winner) this.turn = this.turn === 'X' ? 'O' : 'X';
    return true;
  }

  checkWinner() {
    const lines = [
      [0, 1, 2], [3, 4, 5], [6, 7, 8], // rows
      [0, 3, 6], [1, 4, 7], [2, 5, 8], // cols
      [0, 4, 8], [2, 4, 6],            // diagonals
    ];
    for (const [a, b, c] of lines) {
      if (this.board[a] && this.board[a] === this.board[b] && this.board[a] === this.board[c]) {
        return this.board[a];
      }
    }
    return this.board.every(Boolean) ? 'draw' : null;
  }
}

function promisify(fn) {
  return function (...args) {
    return new Promise((resolve, reject) => {
      fn.apply(this, [
        ...args,
        (err, ...results) => {
          if (err) reject(err);
          else resolve(results.length > 1 ? results : results[0]);
        },
      ]);
    });
  };
}

