class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key) {
    if (!this.map.has(key)) return -1;
    const value = this.map.get(key);
    this.map.delete(key);   // remove...
    this.map.set(key, value); // ...re-insert as newest
    return value;
  }

  put(key, value) {
    if (this.map.has(key)) this.map.delete(key);
    else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value); // evict oldest
    }
    this.map.set(key, value);
  }
}

async function retry(fn, times = 3, delay = 100) {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch (err) {
      attempt++;
      if (attempt >= times) throw err;
      const wait = delay * 2 ** (attempt - 1);
      await new Promise((resolve) => setTimeout(resolve, wait));
    }
  }
}

class Typeahead {
  constructor(fetchFn, { delay = 250 } = {}) {
    this.fetchFn = fetchFn;
    this.delay = delay;
    this.results = [];
    this.active = -1;      // highlighted index
    this.timer = null;
    this.requestId = 0;    // guards against stale responses
  }

  input(query) {
    clearTimeout(this.timer);
    if (!query.trim()) { this.results = []; this.active = -1; return; }
    this.timer = setTimeout(() => this.search(query), this.delay);
  }

  async search(query) {
    const id = ++this.requestId;
    const data = await this.fetchFn(query);
    if (id !== this.requestId) return; // stale: a newer request won the race
    this.results = data;
    this.active = -1;
  }

  move(dir) {
    if (!this.results.length) return;
    const n = this.results.length;
    this.active = (this.active + dir + n) % n; // wraparound both directions
  }

  select() {
    return this.active >= 0 ? this.results[this.active] : null;
  }
}
